-- The workbench homepage reads stationLetter protocol config on load and
-- expects a JSON configValue object. The entity uses AESEncryptHandler, so
-- seed the default disabled config as the encrypted value generated by the
-- notification-admin service.
INSERT INTO public.notice_protocol_config (
  id,
  protocol,
  config_value,
  creator,
  create_time,
  create_staff_id,
  modifier,
  modify_time,
  modify_staff_id
)
VALUES (
  1001,
  'stationLetter',
  '',
  'default',
  CURRENT_TIMESTAMP,
  1,
  'default',
  CURRENT_TIMESTAMP,
  1
)
ON CONFLICT (id) DO UPDATE
SET protocol = EXCLUDED.protocol,
    config_value = EXCLUDED.config_value,
    modifier = EXCLUDED.modifier,
    modify_time = CURRENT_TIMESTAMP,
    modify_staff_id = EXCLUDED.modify_staff_id;
